module multiplier(
    input [3:0] a,
    input [3:0] b,
    output [7:0] product
);
    wire [7:0] p0, p1, p2, p3;

    wire neg_product = b[0];
    assign p0 = neg_product ? {4'b0000, a} : 8'b00000000;
    assign p1 = b[1] ? {3'b000, a, 1'b0} : 8'b00000000;
    assign p2 = b[2] ? {2'b00, a, 2'b00} : 8'b00000000;
    assign p3 = b[3] ? {1'b0, a, 3'b000} : 8'b00000000;

    assign product = p0 + p1 + p2 + p3;
endmodule
